const MATRIX = {
  'CREATIVE':       { primary: 'claude-sonnet-4-6',  fallback: 'gpt-4o' },
  'PERSONAL':       { primary: 'claude-sonnet-4-6',  fallback: 'gpt-4o' },
  'JOB.marketing':  { primary: 'gemini-1.5-flash',   fallback: 'gpt-4o-mini' },
  'JOB.ops':        { primary: 'gemini-1.5-flash',   fallback: 'gpt-4o-mini' },
  'Long-context':   { primary: 'gemini-1.5-pro',     fallback: 'claude-sonnet-4-6' },
  'default':        { primary: 'gemini-1.5-flash',   fallback: 'ollama/llama3.1' }
};
const FALLBACK_CHAIN = [
  'claude-sonnet-4-6','gpt-4o','gemini-1.5-pro','gemini-1.5-flash','ollama/llama3.1'
];
const AGENT_MAP = { JOB: 'jeff', PERSONAL: 'eilinaire', CREATIVE: 'ego_era' };

const input     = $input.first().json;
const pillar    = (input.pillar || 'default').toUpperCase();
const reduced   = input.reduced_mode === true;
const throttled = {};

// Build throttle map from rate_limit_registry results
for (const row of $('Check Rate Limits').all()) {
  if (row.json.is_throttled) throttled[row.json.provider] = true;
}

const matrixKey = Object.keys(MATRIX).find(k => pillar.startsWith(k.toUpperCase())) || 'default';
let { primary, fallback } = MATRIX[matrixKey];

// Walk fallback chain if throttled
let selectedModel = reduced ? 'gemini-1.5-flash' : primary;
if (throttled[selectedModel]) {
  selectedModel = FALLBACK_CHAIN.find(m => !throttled[m]) || 'ollama/llama3.1';
}

const topPillar = pillar.split('.')[0];
const assignedAgent = AGENT_MAP[topPillar] || 'jeff';

return [{ json: {
  assigned_agent:  assignedAgent,
  selected_model:  selectedModel,
  pillar:          pillar,
  reduced_mode:    reduced,
  message:         input.message || '',
  routed_at:       new Date().toISOString()
}}];
